import React from "react";
import { Link, useLocation } from "react-router-dom";
import { BookingRecord, Bus } from "../types";

type ConfirmationState = {
  booking?: BookingRecord;
  bus?: Bus;
  successMessage?: string;
};

const Confirmation: React.FC = () => {
  const location = useLocation();
  const state = (location.state || {}) as ConfirmationState;

  if (!state.booking || !state.bus) {
    return (
      <section className="rounded-2xl bg-white p-8 text-center shadow-travel ring-1 ring-slate-200">
        <h2 className="text-2xl font-bold text-slate-900">No booking found</h2>
        <Link to="/" className="mt-4 inline-block rounded-lg bg-blue-600 px-4 py-2 text-white">
          Back to Home
        </Link>
      </section>
    );
  }

  return (
    <section className="mx-auto max-w-3xl rounded-2xl bg-white p-8 shadow-travel ring-1 ring-slate-200">
      <p className="text-sm font-semibold uppercase tracking-wide text-emerald-600">{state.successMessage || "Booking Successful"}</p>
      <h2 className="mt-2 text-3xl font-bold text-slate-900">Ticket Summary</h2>

      <div className="mt-6 grid gap-4 md:grid-cols-2">
        <div className="rounded-xl bg-slate-50 p-4 ring-1 ring-slate-200">
          <p className="text-xs uppercase text-slate-500">Booking ID</p>
          <p className="mt-1 text-lg font-bold text-slate-900">{state.booking.bookingCode}</p>
        </div>
        <div className="rounded-xl bg-slate-50 p-4 ring-1 ring-slate-200">
          <p className="text-xs uppercase text-slate-500">Status</p>
          <p className="mt-1 text-lg font-bold text-emerald-600">{state.booking.status}</p>
        </div>
      </div>

      <div className="mt-6 grid gap-6 md:grid-cols-2">
        <div className="space-y-3 text-sm text-slate-700">
          <p><span className="font-semibold">Operator:</span> {state.booking.operatorName || state.bus.operatorName}</p>
          <p><span className="font-semibold">Route:</span> {state.booking.route}</p>
          <p><span className="font-semibold">Boarding Point:</span> {state.booking.boardingPoint}</p>
          <p><span className="font-semibold">Dropping Point:</span> {state.booking.droppingPoint}</p>
          <p><span className="font-semibold">Seat Numbers:</span> {state.booking.selectedSeats.join(", ")}</p>
          <p><span className="font-semibold">Payment Method:</span> {state.booking.paymentMethod}</p>
          <p><span className="font-semibold">Total Price:</span> INR {state.booking.totalPrice}</p>
        </div>

        <div>
          <h3 className="text-lg font-semibold text-slate-900">Passenger Details</h3>
          <div className="mt-3 space-y-3">
            {state.booking.passengerDetails.map((passenger) => (
              <div key={`${passenger.seatNumber}-${passenger.name}`} className="rounded-xl bg-slate-50 p-4 text-sm text-slate-700 ring-1 ring-slate-200">
                <p className="font-semibold text-slate-900">Seat {passenger.seatNumber}</p>
                <p>{passenger.name}</p>
                <p>Age {passenger.age} | {passenger.gender}</p>
              </div>
            ))}
          </div>
        </div>
      </div>

      <div className="mt-8 flex flex-wrap gap-3">
        <Link to="/" className="rounded-lg bg-blue-600 px-4 py-2.5 font-semibold text-white transition hover:bg-blue-700">
          Back to Home
        </Link>
        <Link to="/my-bookings" className="rounded-lg border border-slate-300 px-4 py-2.5 font-semibold text-slate-700 transition hover:bg-slate-100">
          View My Bookings
        </Link>
      </div>
    </section>
  );
};

export default Confirmation;
